/**
 * Field-level copy for the /setup/review form editor (Stream 3).
 *
 * Each entry binds a `(sectionId, fieldKey)` to:
 *   - label:       short Title-Case label shown above the input
 *   - help:        one-sentence guidance shown beneath the input (muted)
 *   - placeholder: ghost text inside the input itself
 *
 * Granular `(section, field)` entries cover `company_context.yaml` because
 * its schema is deterministic — see `src/lib/framework/context-types.ts`
 * (`CompanyContext`). The synthesized YAML/Markdown/text sections are
 * mostly long-form prose generated by the LLM with shape that varies run
 * to run. For those we surface a single coarse "file" entry under the
 * synthetic field name `__file__` so the editor can render a labeled
 * textarea over the raw body without inventing fields the schema doesn't
 * pin down.
 *
 * Field keys mirror the dotted path inside the parsed YAML (e.g.
 * `company.name`, `icp.segments_freeform`). Array fields use `[]` to
 * indicate a list (e.g. `icp.pain_points[]`). The editor renders these as
 * one-item-per-line textareas.
 */

export interface FieldHelp {
  label: string
  help: string
  placeholder?: string
}

export type SectionFieldHelp = Record<string, FieldHelp>

