/**
 * Resolve help for a `(sectionId, fieldKey)` pair, falling back to a
 * minimal label derived from the field key when no entry is registered.
 * This guarantees the form always has a label even if the schema gains a
 * field before the help registry catches up.
 */
export function resolveFieldHelp(sectionId: string, fieldKey: string): FieldHelp {
  const section = SETUP_FIELD_HELP[sectionId]
  if (section && section[fieldKey]) return section[fieldKey]
  // Derive a Title Case label from the leaf segment of the key.
  const leaf = fieldKey.replace(/\[\]$/, '').split('.').pop() ?? fieldKey
  const label = leaf
    .replace(/[_-]+/g, ' ')
    .replace(/([a-z])([A-Z])/g, '$1 $2')
    .split(/\s+/)
    .filter(Boolean)
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
    .join(' ')
  return { label, help: '' }
}
